  category: text('category').notNull(),
  definition: jsonb('definition').notNull(),
  parameters: jsonb('parameters').notNull(),
  assumptions: jsonb('assumptions').notNull().$defaultFn(() => []),
  version: integer('version').notNull().default(1),
