    references: [pipelines.id],
  }),
  triggerEvent: one(triggerEvents, {
    fields: [pipelineExecutions.triggerEventId],
    references: [triggerEvents.id],
  }),
  executionSteps: many(executionSteps),
  reviewDecisions: many(reviewDecisions),
