  execution: one(pipelineExecutions, {
    fields: [reviewDecisions.executionId],
    references: [pipelineExecutions.id],
  }),
  executionStep: one(executionSteps, {
    fields: [reviewDecisions.executionStepId],
    references: [executionSteps.id],
  }),
}));

