 37→
 38→### T008: Define EventBus interface and EventEnvelope types (`src/pipelines/event-bus/interface.ts`)
 39→
 40→**Purpose**: Establish the contract that all event bus implementations must satisfy so that tests can use an in-memory stub and production uses `PgNotifyBus`.
 41→
 42→**Steps**:
 43→1. Create `src/pipelines/event-bus/interface.ts`
 44→2. Define `EventEnvelope` — the typed container for all events passing through the bus
 45→3. Define `EventBus` interface with `publish`, `subscribe`, `unsubscribe`, and `close`
 46→4. Define `EventHandler` callback type
 47→
 48→```typescript
 49→// src/pipelines/event-bus/interface.ts
 50→import type { TriggerType } from '../types';
 51→
 52→export interface EventEnvelope {
 53→  id: string;           // UUID — matches trigger_events.id
 54→  tenantId: string;     // UUID
 55→  eventType: TriggerType;
 56→  payload: Record<string, unknown>;
 57→  createdAt: Date;
 58→}
 59→
 60→export type EventHandler = (event: EventEnvelope) => Promise<void>;
 61→
 62→export interface EventBus {
 63→  /**
 64→   * Publish an event. Persists to trigger_events table and sends NOTIFY.
 65→   * Returns the persisted event ID.
 66→   */
 67→  publish(
 68→    tenantId: string,
 69→    eventType: TriggerType,
 70→    payload: Record<string, unknown>,
 71→  ): Promise<string>;
 72→
 73→  /**
 74→   * Subscribe to all events matching the given type.
 75→   * Handler is called with the full EventEnvelope after DB fetch.
 76→   * Returns a subscription ID for unsubscribing.
 77→   */
 78→  subscribe(eventType: TriggerType, handler: EventHandler): string;
 79→
 80→  /**
 81→   * Remove a subscription by ID.
 82→   */
 83→  unsubscribe(subscriptionId: string): void;
 84→
 85→  /**
 86→   * Gracefully shut down the bus (close LISTEN connection, flush pending).
 87→   */
 88→  close(): Promise<void>;
 89→}
 90→
 91→/**
 92→ * In-memory event bus for testing. Calls handlers synchronously in-process.
 93→ */
 94→export class InMemoryEventBus implements EventBus {
 95→  private handlers = new Map<TriggerType, Map<string, EventHandler>>();
 96→  private counter = 0;
 97→
 98→  async publish(tenantId: string, eventType: TriggerType, payload: Record<string, unknown>): Promise<string> {
 99→    const id = `test-event-${++this.counter}`;
100→    const envelope: EventEnvelope = { id, tenantId, eventType, payload, createdAt: new Date() };
101→    const subs = this.handlers.get(eventType);
102→    if (subs) {
103→      for (const handler of subs.values()) {
104→        await handler(envelope);
105→      }
106→    }
107→    return id;
108→  }
109→
110→  subscribe(eventType: TriggerType, handler: EventHandler): string {
111→    if (!this.handlers.has(eventType)) this.handlers.set(eventType, new Map());
112→    const id = `sub-${++this.counter}`;
113→    this.handlers.get(eventType)!.set(id, handler);
114→    return id;
115→  }
116→
117→  unsubscribe(subscriptionId: string): void {
118→    for (const subs of this.handlers.values()) {
119→      subs.delete(subscriptionId);
120→    }
121→  }
122→
123→  async close(): Promise<void> {
124→    this.handlers.clear();
125→  }
126→}
127→```
