107→// src/pipelines/triggers/corpus-change.ts
108→import type { TriggerHandler, TriggerContext, TriggerResult } from './interface';
109→import type { Pipeline } from '../types';
110→import type { CorpusChangeTriggerConfig } from '../types';
111→import { MAX_PIPELINE_DEPTH } from '../types';
