113→export class CorpusChangeTriggerHandler implements TriggerHandler {
114→  readonly triggerType = 'corpus_change' as const;
115→
116→  canHandle(eventType: string): boolean {
117→    return eventType === 'corpus_change';
118→  }
119→
120→  getMatchingPipelines(context: TriggerContext, activePipelines: Pipeline[]): TriggerResult[] {
121→    // Runtime depth guard — secondary defense after DFS cycle detection
122→    if (context.currentDepth >= MAX_PIPELINE_DEPTH) {
123→      console.warn(
124→        `[CorpusChangeTrigger] Max depth ${MAX_PIPELINE_DEPTH} reached for tenant ${context.tenantId}. Stopping.`,
125→      );
126→      return [];
127→    }
128→
129→    const changedSourceId = context.event.payload?.sourceId as string | undefined;
130→
131→    return activePipelines
132→      .filter((p) => p.triggerType === 'corpus_change')
133→      .filter((p) => {
134→        const cfg = p.triggerConfig as CorpusChangeTriggerConfig;
135→        // Empty sourceIds means "trigger on any source change"
136→        if (!cfg.sourceIds || cfg.sourceIds.length === 0) return true;
137→        return changedSourceId ? cfg.sourceIds.includes(changedSourceId) : false;
138→      })
139→      .map((p) => ({
140→        pipelineId: p.id,
141→        triggerPayload: {
142→          sourceId: changedSourceId,
143→          changeCount: context.event.payload?.changeCount,
144→          depth: context.currentDepth + 1,
145→        },
146→      }));
147→  }
148→}
