203→    const cfg = pipeline.triggerConfig as ManualTriggerConfig;
204→    if (cfg.allowedRoles && cfg.allowedRoles.length > 0) {
205→      if (!requestorRole || !cfg.allowedRoles.includes(requestorRole)) {
206→        console.warn(`[ManualTrigger] Role '${requestorRole}' not allowed for pipeline ${pipelineId}`);
207→        return [];
208→      }
209→    }
