286→### T016: Build DFS cycle detector and dependency graph builder (`src/pipelines/graph/`)
287→
288→**Purpose**: Prevent pipeline configurations where pipeline A triggers pipeline B (via corpus_change) which in turn triggers pipeline A — infinite loops. Run at pipeline creation/update time.
289→
290→**Steps**:
291→1. Create `src/pipelines/graph/cycle-detector.ts`
292→2. Define `PipelineNode` — represents a pipeline in the dependency graph
293→3. Define `buildDependencyGraph` — constructs an adjacency list from all active pipelines
294→4. Define `detectCycle` — DFS traversal that returns the cycle path if found, or null
295→5. Define `validateNoCycle` — top-level function used by the API layer
296→
297→```typescript
298→// src/pipelines/graph/cycle-detector.ts
299→import type { Pipeline } from '../types';
300→
301→export interface PipelineNode {
302→  id: string;
303→  triggerType: string;
304→  sourceIds: string[];  // for corpus_change triggers
305→}
306→
307→export type DependencyGraph = Map<string, Set<string>>;
308→
309→/**
310→ * Build an adjacency list: pipeline A -> Set<pipeline B> means
311→ * "if A runs and modifies corpus, B may trigger".
312→ *
313→ * For corpus_change pipelines, edges are created when:
314→ * - A has content_generation or similar steps that write to corpus
315→ * - B has a corpus_change trigger matching the sources A writes to
316→ *
317→ * For this implementation, we conservatively assume any pipeline with
318→ * content_generation steps can trigger any corpus_change pipeline for
319→ * the same tenant.
320→ */
321→export function buildDependencyGraph(pipelines: Pipeline[]): DependencyGraph {
322→  const graph: DependencyGraph = new Map();
323→
324→  for (const p of pipelines) {
325→    graph.set(p.id, new Set());
326→  }
327→
328→  const corpusWriters = pipelines.filter((p) =>
329→    (p.stepConfigs as Array<{ stepType: string }>).some(
330→      (s) => s.stepType === 'content_generation' || s.stepType === 'profile_generation',
331→    ),
332→  );
333→
334→  const corpusChangeListeners = pipelines.filter((p) => p.triggerType === 'corpus_change');
335→
336→  for (const writer of corpusWriters) {
337→    for (const listener of corpusChangeListeners) {
338→      if (writer.id !== listener.id) {
339→        graph.get(writer.id)!.add(listener.id);
340→      }
341→    }
342→  }
343→
344→  return graph;
345→}
346→
347→/**
348→ * DFS cycle detection. Returns the cycle path (array of pipeline IDs) if a
349→ * cycle is found, or null if the graph is acyclic.
350→ */
351→export function detectCycle(
352→  graph: DependencyGraph,
353→  startId: string,
354→): string[] | null {
355→  const visited = new Set<string>();
356→  const path: string[] = [];
357→
358→  function dfs(nodeId: string): boolean {
359→    if (path.includes(nodeId)) {
360→      // Found cycle — return the cycle portion of the path
361→      return true;
362→    }
363→    if (visited.has(nodeId)) return false;
364→
365→    visited.add(nodeId);
366→    path.push(nodeId);
367→
368→    for (const neighbor of graph.get(nodeId) ?? []) {
369→      if (dfs(neighbor)) return true;
370→    }
371→
372→    path.pop();
373→    return false;
374→  }
375→
376→  return dfs(startId) ? [...path] : null;
377→}
378→
379→/**
380→ * Top-level validation function called during pipeline create/update.
381→ * Throws if creating/updating the given pipeline would introduce a cycle.
382→ */
383→export function validateNoCycle(
384→  newPipeline: Pick<Pipeline, 'id' | 'triggerType' | 'stepConfigs'>,
385→  existingPipelines: Pipeline[],
386→): void {
387→  // Add the new pipeline to the set and build the graph
388→  const allPipelines = [
389→    ...existingPipelines.filter((p) => p.id !== newPipeline.id),
390→    newPipeline as Pipeline,
391→  ];
392→  const graph = buildDependencyGraph(allPipelines);
393→  const cycle = detectCycle(graph, newPipeline.id);
394→
395→  if (cycle) {
396→    throw new Error(
397→      `Pipeline configuration would create a circular dependency: ${cycle.join(' → ')}`,
398→    );
399→  }
400→}
401→```
402→
