  it('returns null for an acyclic graph', () => {
    const graph = new Map([
      ['A', new Set(['B'])],
      ['B', new Set(['C'])],
      ['C', new Set()],
    ]);
    expect(detectCycle(graph, 'A')).toBeNull();
